import React, { useState, useEffect } from 'react';
import DisplayStockData from './Stock';
import './Stock.css'
import mid from '../mid.png';

function View() {
  const [symbols, setSymbols] = useState([]);
  const [stockData, setStockData] = useState([]);
  const stocks = ['BPL', 'UPL', 'ITC'];
  const [selectedStock, setSelectedStock] = useState(null);
  const [selectedStockData, setSelectedStockData] = useState(null);

  async function fetchStockData(symbol) {
    const response = await fetch(`http://127.0.0.1:8000/${symbol}/`);
    const data = await response.json();
    if (data.hasOwnProperty('error')) {
      alert(data.error);
      return null;
    }
    return data;
  }

  async function handleStockClick(stock) {
    setSelectedStock(stock);
    const data = await fetchStockData(stock);
    setSelectedStockData(data);
  }

  const handleAddSymbol = async symbol => {
    if (symbols.length < 9 && !symbols.includes(symbol)) {
      const data = await fetchStockData(symbol);
      if (data) {
        setSymbols([...symbols, symbol]);
        setStockData([...stockData, data]);
      }
    } else {
      alert("Symbol already entered or maximum limit reached (9)");
    }
  };

  const handleRemoveSymbol = symbol => {
    setSymbols(symbols.filter(item => item !== symbol));
    setStockData(stockData.filter(item => item.symbol !== symbol));
  };

  const [sensexData, setSensexData] = useState({});
  const arrow = sensexData.change > 0 ? '\u25B2' : '\u25BC';
  useEffect(() => {
    const fetchSensexData = async () => {
      const response = await fetch('http://127.0.0.1:8000/BSE/');
      const data = await response.json();
      setSensexData(data);
    };
    fetchSensexData();
  }, []);

  useEffect(() => {
    let sockets = [];
    if (stockData.length) {
      stockData.forEach(data => {
        const socket = new WebSocket(`ws://127.0.0.1:8000/ws/stock/${data.symbol}/`);
        socket.onmessage = event => {
          const updatedData = JSON.parse(event.data);
          setStockData(prevData => prevData.map(item => (item.symbol === updatedData.symbol ? updatedData : item)));
        };
        sockets.push(socket);
      });
    }
    return () => {
      sockets.forEach(socket => socket.close());
    };
  }, [stockData]);

  return (
    <div>
      <div>
        <div className="info-container">
          {stockData.map(data => (
            <div key={data.symbol} >
              <DisplayStockData stockData={data} />
              {/* <button onClick={() => handleRemoveSymbol(data.symbol)}>&#10799;</button> */}
            </div>
          ))}
        </div>
      </div>
      <div className='grid'>
        <form
          onSubmit={event => {
            event.preventDefault();
            const symbol = event.target.symbol.value.toUpperCase();
            handleAddSymbol(symbol);
            event.target.symbol.value = '';
          }}
        >
          <div className='two item'>
            <input type="text" placeholder='enter stock' name="symbol"></input>
            {/* <button type="submit" >+</button> */}
          </div>
        </form>
        {symbols.length > 0 ? (
          <div className='four item'>
            <div className="circles-grid">
              {[...Array(9)].map((_, i) => (
                <div
                  key={i}
                  className={`circle ${i < symbols.length ? "black" : "red"}`}
                ></div>
              ))}
            </div>
            <div className="symbol-count">
              <button className='but' onClick={() => {
                setSymbols([]);
                setStockData([]);
              }}>X</button>
              <span className="symbol-length">{symbols.length}</span> / 9 &nbsp;
            </div>
          </div>
        ) : (
          <div className='four item'>
            <div className="circles-grid">
              {[...Array(9)].map((_, i) => (
                <div key={i} className="circle red"></div>
              ))}
            </div>
            <div className="symbol-count">
              <span className="symbol-length">{symbols.length}</span> / 9 &nbsp;
            </div>
          </div>
        )}
        <div className='six f19 item in-grid iga'>
          <div className='ione'>
            {sensexData && (
              <>
                <h3><img src={mid} alt="Logo" width="30" height="30" />&nbsp;BSE SENSEX</h3>
                <div className="sensex-container">
                  <div className="sensex-data">
                    <span className="sensex-value">{sensexData.value}</span>
                    <span className="sensex-change">{arrow} {sensexData.change}</span>
                  </div>
                </div>
              </>
            )}
          </div>
          <div className='ione'>
            {sensexDatai && (
              <>
                <h3><img src={mid} alt="Logo" width="30" height="30" />&nbsp;INFOSYS</h3>
                <div className="sensex-container">
                  <div className="sensex-data">
                    <span className="sensex-value">{sensexDatai.value}</span>
                    <span className="sensex-change">{arrowi} {sensexDatai.change}</span>
                  </div>
                </div>
              </>
            )}
          </div>
        </div>
        <div className='three item'>
          {stocks.map(stock => (
            <a key={stock} onClick={() => handleStockClick(stock)}>{stock}</a>
          ))}
        </div>
        <stock symbol={selectedStock} />
      </div>
    </div>
  );
}
export default View  


























































